+import { object } from "@optique/core/constructs";
+import { formatMessage } from "@optique/core/message";
+import { withDefault } from "@optique/core/modifiers";
+import { conditionalOption, flag, option, requiredWhen } from "@optique/core/primitives";
+import { parseSync } from "@optique/core/parser";
+import { choice, string } from "@optique/core/valueparser";
+import assert from "node:assert/strict";
+import { describe, it } from "node:test";
+
+describe("conditional option dependencies", () => {
+  it("resolves object keys and CLI flags through wrappers", () => {
+    const parser = object({
+      mode: withDefault(option("--mode", choice(["dev", "prod"])), "dev"),
+      deploy: withDefault(option("--deploy", string(), {
+        dependsOn: { option: "--mode", value: "prod" },
+      }), "none"),
+    });
+    const result = parseSync(parser, ["--mode", "prod", "--deploy", "now"]);
+    assert.deepEqual(result, { success: true, value: { mode: "prod", deploy: "now" } });
+  });
+
+  it("requires an unsatisfied dependency when requested", () => {
+    const parser = object({
+      enabled: withDefault(flag("--enabled"), false),
+      output: withDefault(option("--output", string(), {
+        dependsOn: { option: "enabled", required: true },
+      }), "default"),
+    });
+    const result = parseSync(parser, []);
+    assert.ok(!result.success);
+    assert.ok(formatMessage(result.error).includes("requires option"));
+    assert.ok(formatMessage(result.error).includes("--enabled"));
+  });
+
+  it("allows hidden optional dependencies unless a source was explicitly falsy", () => {
+    const parser = object({
+      enabled: withDefault(option("--enabled", choice(["true", "false"])), "false"),
+      extra: withDefault(option("--extra", string(), {
+        dependsOn: { option: "enabled", value: "true" },
+      }), "none"),
+    });
+    const hidden = parser.getDocFragments({ kind: "available", state: parser.initialState }).fragments;
+    assert.equal(JSON.stringify(hidden).includes("--extra"), false);
+    const allowed = parseSync(parser, ["--extra", "value"]);
+    assert.ok(allowed.success);
+    const rejected = parseSync(parser, ["--enabled", "false", "--extra", "value"]);
+    assert.ok(!rejected.success);
+  });
+
+  it("supports compounds, empty groups, and helpers", () => {
+    const parser = object({
+      a: withDefault(flag("--a"), false),
+      b: withDefault(flag("--b"), false),
+      value: withDefault(conditionalOption({ anyOf: [], allOf: [{ option: "--a" }] }, "--value", string()), "none"),
+      required: withDefault(requiredWhen({ allOf: [] }, "--required", string()), "none"),
+    });
