+    assert.ok(result.success);
+    const required = object({ enabled: withDefault(flag("--enabled"), false), value: withDefault(requiredWhen("--enabled", "--value", string()), "none") });
+    const rejected = parseSync(required, []);
+    assert.ok(!rejected.success);
+  });
+});
