+
+/** Creates an option that is required when its condition is not satisfied. */
+export function requiredWhen<M extends Mode, T>(
+  condition: ConditionalOptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  const dependsOn = typeof condition === "string" ? { option: condition } : condition;
+  return conditionalOptionArgs({ ...dependsOn, required: true }, flagSpec, valueParser);
